15762 bool BoUpSLP::isFullyVectorizableTinyTree(bool ForReduction) const {
15763   LLVM_DEBUG(dbgs() << "SLP: Check whether the tree with height "
15764                     << VectorizableTree.size() << " is fully vectorizable .\n");
15765 
15766   auto &&AreVectorizableGathers = [this](const TreeEntry *TE, unsigned Limit) {
15767     SmallVector<int> Mask;
15768     return TE->isGather() &&
15769            !any_of(TE->Scalars,
15770                    [this](Value *V) { return EphValues.contains(V); }) &&
15771            (allConstant(TE->Scalars) || isSplat(TE->Scalars) ||
15772             TE->Scalars.size() < Limit ||
15773             (((TE->hasState() &&
15774                TE->getOpcode() == Instruction::ExtractElement) ||
15775               all_of(TE->Scalars, IsaPred<ExtractElementInst, UndefValue>)) &&
15776              isFixedVectorShuffle(TE->Scalars, Mask, AC)) ||
15777             (TE->hasState() && TE->getOpcode() == Instruction::Load &&
15778              !TE->isAltShuffle()) ||
15779             any_of(TE->Scalars, IsaPred<LoadInst>));
15780   };
15781 
15782   // We only handle trees of heights 1 and 2.
15783   if (VectorizableTree.size() == 1 &&
15784       (VectorizableTree[0]->State == TreeEntry::Vectorize ||
15785        VectorizableTree[0]->State == TreeEntry::StridedVectorize ||
15786        VectorizableTree[0]->State == TreeEntry::CompressVectorize ||
15787        (ForReduction &&
15788         AreVectorizableGathers(VectorizableTree[0].get(),
15789                                VectorizableTree[0]->Scalars.size()) &&
15790         VectorizableTree[0]->getVectorFactor() > 2)))
15791     return true;
15792 
15793   if (VectorizableTree.size() != 2)
15794     return false;
15795 
15796   // Handle splat and all-constants stores. Also try to vectorize tiny trees
15797   // with the second gather nodes if they have less scalar operands rather than
15798   // the initial tree element (may be profitable to shuffle the second gather)
15799   // or they are extractelements, which form shuffle.
15800   if (VectorizableTree[0]->State == TreeEntry::Vectorize &&
15801       AreVectorizableGathers(VectorizableTree[1].get(),
15802                              VectorizableTree[0]->Scalars.size()))
15803     return true;
15804 
15805   // Gathering cost would be too much for tiny trees.
15806   if (VectorizableTree[0]->isGather() ||
15807       (VectorizableTree[1]->isGather() &&
15808        VectorizableTree[0]->State != TreeEntry::ScatterVectorize &&
15809        VectorizableTree[0]->State != TreeEntry::StridedVectorize &&
15810        VectorizableTree[0]->State != TreeEntry::CompressVectorize))
15811     return false;
15812 
15813   return true;
15814 }
