15816 static bool isLoadCombineCandidateImpl(Value *Root, unsigned NumElts,
15817                                        TargetTransformInfo *TTI,
15818                                        bool MustMatchOrInst) {
15819   // Look past the root to find a source value. Arbitrarily follow the
15820   // path through operand 0 of any 'or'. Also, peek through optional
15821   // shift-left-by-multiple-of-8-bits.
15822   Value *ZextLoad = Root;
15823   const APInt *ShAmtC;
15824   bool FoundOr = false;
15825   while (!isa<ConstantExpr>(ZextLoad) &&
15826          (match(ZextLoad, m_Or(m_Value(), m_Value())) ||
15827           (match(ZextLoad, m_Shl(m_Value(), m_APInt(ShAmtC))) &&
15828            ShAmtC->urem(8) == 0))) {
15829     auto *BinOp = cast<BinaryOperator>(ZextLoad);
15830     ZextLoad = BinOp->getOperand(0);
15831     if (BinOp->getOpcode() == Instruction::Or)
15832       FoundOr = true;
15833   }
15834   // Check if the input is an extended load of the required or/shift expression.
15835   Value *Load;
15836   if ((MustMatchOrInst && !FoundOr) || ZextLoad == Root ||
15837       !match(ZextLoad, m_ZExt(m_Value(Load))) || !isa<LoadInst>(Load))
15838     return false;
